import React from 'react';
import { FlagIconsByCode } from '../../Flags';
import type { Country } from '../Countries.const';

type FlagProps = {
	value: Country;
};

const FlagComponent: React.FC<FlagProps> = ({ value }) => {
	const Icon = FlagIconsByCode[value.nameCode];

	if (!Icon) {
		return null;
	}

	return <Icon width={20} height={20} role="img" aria-label={value.nameCode} focusable="false" />;
};

export const Flag = React.memo(FlagComponent);
